const MAX_TASK_LENGTH = 64;
const body = ($json && $json.body) || {};
const content = (typeof body.content === 'string' ? body.content : '').trim();
const requestId = typeof body.request_id === 'string' ? body.request_id.trim() : '';
const sender = typeof body.sender === 'string' ? body.sender.trim() : '';

const HELP_TEXT = '未能识别指令，请使用以下格式之一：\n\n结构化格式：\n@AI秘书处\n员工：AI CEO\n任务：生成今日经营分析\n优先级：普通\n\n简单格式：\n让AI CEO生成今日经营分析\n\n查询任务：\n查询 TASK-XXXXXXXXXXXX';

function invalidResult() {
  return {
    json: {
      type: 'invalid',
      request_id: requestId,
      reply_text: HELP_TEXT,
    },
  };
}

function priorityFromText(text) {
  const t = (text || '').trim();
  if (t === '高' || t === '紧急') return 'high';
  if (t === '低') return 'low';
  return 'normal';
}

if (!requestId) {
  return invalidResult();
}

// 查询指令：查询/任务状态/查看 + TASK-xxxx（确定性正则匹配，
// 不使用大模型猜测）。查询类消息不创建任务。
const queryMatch = content.match(/(?:查询|任务状态|查看)\s*(TASK-[A-Za-z0-9]+)/);
if (queryMatch) {
  return {
    json: {
      type: 'query',
      request_id: requestId,
      task_id: queryMatch[1],
    },
  };
}

// 结构化提交格式：@AI秘书处 / 员工：xxx / 任务：xxx / 优先级：xxx（可选）。
if (content.indexOf('@AI秘书处') !== -1 || /员工[：:]/.test(content)) {
  const agentMatch = content.match(/员工[：:]\s*([^\n]+)/);
  const taskMatch = content.match(/任务[：:]\s*([^\n]+)/);
  const priorityMatch = content.match(/优先级[：:]\s*([^\n]+)/);

  const assignedAgent = agentMatch ? agentMatch[1].trim() : '';
  const task = taskMatch ? taskMatch[1].trim() : '';

  if (!assignedAgent || !task || task.length > MAX_TASK_LENGTH) {
    return invalidResult();
  }

  return {
    json: {
      type: 'submit',
      request_id: requestId,
      assigned_agent: assignedAgent,
      task,
      priority: priorityFromText(priorityMatch ? priorityMatch[1] : ''),
      context: { channel: 'wecom', sender },
    },
  };
}

// 简单格式：让<Agent><动词><任务内容>，只做确定性结构切分，
// 不猜测、不使用大模型、不在 n8n 中维护 Agent 名册——是否真的
// 存在这个 Agent，由后端 AgentRegistry 在提交时校验。
const simpleMatch = content.match(/^让([^，,。]+?)(生成|执行|完成|处理|做|准备|制作)(.+)$/);
if (simpleMatch) {
  const assignedAgent = simpleMatch[1].trim();
  const task = (simpleMatch[2] + simpleMatch[3]).trim();

  if (!assignedAgent || !task || task.length > MAX_TASK_LENGTH) {
    return invalidResult();
  }

  return {
    json: {
      type: 'submit',
      request_id: requestId,
      assigned_agent: assignedAgent,
      task,
      priority: 'normal',
      context: { channel: 'wecom', sender },
    },
  };
}

return invalidResult();

const parseItem = $('Code｜解析指令').item.json;
const type = parseItem.type;

function safeAgentText(agent) {
  return agent || '（未指定）';
}

function extractStatusCode(errorLike) {
  const error = (errorLike && errorLike.error) || {};
  const candidates = [
    error.httpCode,
    error.statusCode,
    error.status,
    error.cause && error.cause.response && error.cause.response.status,
  ];
  for (const candidate of candidates) {
    if (candidate === undefined || candidate === null) continue;
    const parsed = parseInt(candidate, 10);
    if (!Number.isNaN(parsed)) return parsed;
  }
  return null;
}

if (type === 'invalid') {
  return { json: { ok: true, reply_text: parseItem.reply_text } };
}

const item = $input.first().json;

if (type === 'submit') {
  if (item && typeof item === 'object' && item.id && item.duplicate !== undefined) {
    const statusLabel = item.duplicate ? '该请求已收到，返回原有任务' : '任务已提交';
    const reply = `${statusLabel}\n任务编号：${item.id}\nAI 员工：${safeAgentText(item.assigned_agent)}\n当前状态：等待执行\n\n发送"查询 ${item.id}"可查看进度。`;
    return { json: { ok: true, reply_text: reply } };
  }

  const statusCode = extractStatusCode(item);
  if (statusCode === 404) {
    return { json: { ok: true, reply_text: `指定的 AI 员工「${parseItem.assigned_agent}」不存在，请检查员工名称后重试。` } };
  }
  if (statusCode === 422 || statusCode === 400) {
    return { json: { ok: true, reply_text: '任务内容不符合要求，请检查格式后重试。' } };
  }
  if (statusCode === 401) {
    return { json: { ok: true, reply_text: '系统鉴权异常，请联系管理员。' } };
  }
  if (statusCode === 503) {
    return { json: { ok: true, reply_text: '任务网关暂未配置，请联系管理员。' } };
  }
  return { json: { ok: true, reply_text: '任务提交暂时失败，请稍后重试。' } };
}

if (type === 'query') {
  const STATUS_TEXT = { pending: '等待执行', running: '执行中', completed: '已完成', failed: '失败' };

  if (item && typeof item === 'object' && item.id && item.status) {
    const statusText = STATUS_TEXT[item.status] || item.status;
    let reply = `任务编号：${item.id}\n当前状态：${statusText}\nAI 员工：${safeAgentText(item.assigned_agent)}\n优先级：${item.priority}\n创建时间：${item.created_at}`;
    if (item.completed_at) {
      reply += `\n完成时间：${item.completed_at}`;
    }
    if (item.status === 'completed') {
      reply += `\n\n执行结果：\n${item.safe_result}`;
    } else if (item.status === 'failed') {
      reply += `\n\n错误信息：\n${item.safe_error}`;
    }
    return { json: { ok: true, reply_text: reply } };
  }

  const statusCode = extractStatusCode(item);
  if (statusCode === 404) {
    return { json: { ok: true, reply_text: `未找到任务：${parseItem.task_id}，请检查任务编号是否正确。` } };
  }
  if (statusCode === 401) {
    return { json: { ok: true, reply_text: '系统鉴权异常，请联系管理员。' } };
  }
  return { json: { ok: true, reply_text: '查询暂时失败，请稍后重试。' } };
}

return { json: { ok: true, reply_text: '系统异常，请稍后重试。' } };
